import re
from datetime import datetime, timedelta

def detect_stale_references(messages, hours_threshold=2):
    recent_threshold = datetime.now() - timedelta(hours=hours_threshold)
    stale_refs = []

    for msg in messages:
        content = msg.content.lower()
        # Look for temporal references
        if re.search(r'(earlier|before|previously|last week|days ago)', content):
            if msg.timestamp < recent_threshold:
                stale_refs.append({
                    'message_id': msg.id,
                    'age_hours': (datetime.now() - msg.timestamp).total_seconds() / 3600,
                    'content_snippet': content[:100]
                })

    return {'stale_references': stale_refs} if stale_refs else None

